// ─── Cross-validation: agree with deterministic agents? ──────────
// Compares the deep_dividend verdict against:
//   - dividend_cut_warning agent (deterministic FCF math)
//   - analyst_downgrade agent (FMP grades)
//   - insider_radar agent (cluster activity)
//   - quality_safety_scores (numerical)
async function deepDividendCrossValidate(env, ticker, deepVerdict, deepCutProb) {
  const today = new Date().toISOString().slice(0, 10);
  // Look back 30 days for cross-validation signals
  const lookback = new Date(Date.now() - 30 * 86400_000).toISOString().slice(0, 10);

  const sources = {};

  // 1. dividend_cut_warning (deterministic)
  try {
    const cw = await env.DB.prepare(
      `SELECT severity, details FROM agent_insights WHERE agent_name = 'dividend_cut_warning' AND ticker = ? AND fecha >= ? ORDER BY fecha DESC LIMIT 1`
    ).bind(ticker, lookback).first();
    sources.dividend_cut_warning = cw ? { severity: cw.severity, present: true } : { present: false };
  } catch { sources.dividend_cut_warning = { error: true }; }

  // 2. analyst_downgrade
  try {
    const ad = await env.DB.prepare(
      `SELECT severity, details FROM agent_insights WHERE agent_name = 'analyst_downgrade' AND ticker = ? AND fecha >= ? ORDER BY fecha DESC LIMIT 1`
    ).bind(ticker, lookback).first();
    sources.analyst_downgrade = ad ? { severity: ad.severity, present: true } : { present: false };
  } catch { sources.analyst_downgrade = { error: true }; }

  // 3. insider radar
  try {
    const ins = await env.DB.prepare(
      `SELECT severity, details FROM agent_insights WHERE agent_name = 'insider' AND ticker = ? AND fecha >= ? ORDER BY fecha DESC LIMIT 1`
    ).bind(ticker, lookback).first();
    sources.insider = ins ? { severity: ins.severity, present: true } : { present: false };
  } catch { sources.insider = { error: true }; }

  // 4. quality_safety_scores
  try {
    const qs = await env.DB.prepare(
      `SELECT quality_score, safety_score FROM quality_safety_scores WHERE ticker = ? ORDER BY snapshot_date DESC LIMIT 1`
    ).bind(ticker).first();
    sources.quality_safety = qs ? { q: qs.quality_score, s: qs.safety_score, present: true } : { present: false };
  } catch { sources.quality_safety = { error: true }; }

  // Compute agreement score
  // Logic: if deep verdict is TRIM/SELL, count how many other sources also say "stress"
  // If deep verdict is BUY/ACCUMULATE, count how many other sources also say "healthy"
  const isDeepNegative = ["TRIM", "SELL"].includes(deepVerdict);
  const isDeepPositive = ["STRONG_BUY", "BUY", "ACCUMULATE"].includes(deepVerdict);

  let agreementCount = 0;
  let totalSources = 0;

  // dividend_cut_warning: severity high/critical = stress
  if (sources.dividend_cut_warning?.present) {
    totalSources++;
    const stressed = ["high", "critical"].includes(sources.dividend_cut_warning.severity);
    if (isDeepNegative === stressed) agreementCount++;
  }

  if (sources.analyst_downgrade?.present) {
    totalSources++;
    const stressed = ["high", "critical"].includes(sources.analyst_downgrade.severity);
    if (isDeepNegative === stressed) agreementCount++;
  }

  if (sources.insider?.present) {
    totalSources++;
    // insider HIGH severity often means cluster sell = bearish
    const bearish = ["high", "critical"].includes(sources.insider.severity);
    if (isDeepNegative === bearish) agreementCount++;
  }

  if (sources.quality_safety?.present) {
    totalSources++;
    const healthy = (sources.quality_safety.s || 0) >= 70 && (sources.quality_safety.q || 0) >= 70;
    if (isDeepPositive === healthy) agreementCount++;
  }

  return {
    sources,
    agreement_count: agreementCount,
    total_sources: totalSources,
    agreement_pct: totalSources > 0 ? agreementCount / totalSources : null,
    conflict_detected: totalSources > 0 && (agreementCount / totalSources) < 0.5,
  };
}

// ─── Pipeline orchestrator ───────────────────────────────────────
// Loads docs from R2, runs all 4 stages, stores result, returns full output.
async function runDeepDividendPipeline(env, opts = {}) {
  const ticker = String(opts.ticker || "").trim().toUpperCase();
  if (!ticker) throw new Error("ticker required");
  const force = !!opts.force;
  const maxDocs = opts.maxDocs || 12;
  const today = new Date().toISOString().slice(0, 10);

  // 1. Look up ticker in positions to get sector
  const pos = await env.DB.prepare(
    `SELECT ticker, sector, name, last_price, div_ttm, div_yield, shares, usd_value, market_value FROM positions WHERE ticker = ? LIMIT 1`
  ).bind(ticker).first();
  const sector_bucket = pickSectorBucket(pos?.sector || "", ticker);

  // 2. Fetch most recent docs from R2 metadata
  const rs = await env.DB.prepare(`
    SELECT id, doc_type, fiscal_year, fiscal_quarter, filing_date, r2_key, title
    FROM earnings_documents
    WHERE ticker = ?
    ORDER BY (filing_date IS NULL), filing_date DESC, id DESC
    LIMIT ?
  `).bind(ticker, maxDocs).all();
  const docs = rs.results || [];
  if (docs.length === 0) {
    return { ok: false, error: `No documents archived for ${ticker}` };
  }

  // Determine the latest quarter for cache key
  const latestDoc = docs[0];
  const latestQuarter = latestDoc.fiscal_quarter
    ? `${latestDoc.fiscal_year}Q${latestDoc.fiscal_quarter}`
    : `${latestDoc.fiscal_year}FY`;

  // 3. Cache check on deep_dividend_analysis (24h TTL unless force)
  if (!force) {
    const cached = await env.DB.prepare(
      `SELECT id, result_json, created_at FROM deep_dividend_analysis WHERE ticker = ? AND quarter = ? ORDER BY created_at DESC LIMIT 1`
    ).bind(ticker, latestQuarter).first();
    if (cached) {
      const ageHours = (Date.now() / 1000 - (cached.created_at || 0)) / 3600;
      if (ageHours < 24) {
        try {
          return {
            ok: true,
            ticker,
            quarter: latestQuarter,
            cached: true,
            cached_at: new Date((cached.created_at || 0) * 1000).toISOString(),
            result: JSON.parse(cached.result_json),
            stored_id: cached.id,
          };
        } catch { /* fall through to re-run */ }
      }
    }
  }

  // 4. Stage 1: Extract each doc
  const extractions = [];
  let totalCharsExtracted = 0;
  for (const doc of docs) {
    if (totalCharsExtracted >= DEEP_DIVIDEND_MAX_TOTAL) break;
    try {
      const ex = await deepDividendExtractor(env, ticker, doc, sector_bucket, { force });
      extractions.push(ex.json);
      totalCharsExtracted += (DEEP_DIVIDEND_TRUNC[doc.doc_type] || 20000);
    } catch (e) {
      console.error(`[deep-dividend] extract failed for ${ticker} doc ${doc.id}:`, e.message);
    }
  }
  if (extractions.length === 0) {
    return { ok: false, error: `Could not extract any documents for ${ticker}` };
  }

  // 5. Stage 2: Historian
  let historian = null;
  try {
    historian = await deepDividendHistorian(env, ticker, sector_bucket, extractions);
  } catch (e) {
    console.error(`[deep-dividend] historian failed for ${ticker}:`, e.message);
    historian = { error: e.message };
  }

  // 6. Build quantitative baseline
  let baseline = { latest_quarter: latestQuarter };
  try {
    const fmpFin = await env.DB.prepare(`SELECT data FROM fmp_financials_cache WHERE ticker = ?`).bind(ticker).first();
    if (fmpFin?.data) {
      const trend = JSON.parse(fmpFin.data)?.trend || {};
      baseline.trendRevenue6Q = (trend.revenue || []).slice(0, 6);
      baseline.trendFCF6Q = (trend.fcf || []).slice(0, 6);
      baseline.trendDebt4Q = (trend.debt || []).slice(0, 4);
      baseline.trendDivPaid4Q = (trend.dividendsPaid || []).slice(0, 4);
      baseline.trendNetIncome6Q = (trend.netIncome || []).slice(0, 6);
    }
  } catch { /* baseline best-effort */ }

  try {
    const qs = await env.DB.prepare(`SELECT quality_score, safety_score, inputs_json FROM quality_safety_scores WHERE ticker = ? ORDER BY snapshot_date DESC LIMIT 1`).bind(ticker).first();
    if (qs) {
      baseline.qualityScore = qs.quality_score;
      baseline.safetyScore = qs.safety_score;
      try {
        const inputs = JSON.parse(qs.inputs_json || '{}');
        baseline.fcfTTM = inputs.fcfTTM;
        baseline.dividendsPaidTTM = inputs.dividendsPaidTTM;
        baseline.fcfCoverageTTM = inputs.fcfCoverageTTM;
        baseline.payoutRatioWorst = inputs.payoutRatioWorst;
        baseline.debtEbitda = inputs.debtEbitda;
        baseline.streakYears = inputs.streakYears;
      } catch {}
    }
  } catch {}

  if (pos) {
    baseline.position = {
      sector: pos.sector,
      name: pos.name,
      last_price: pos.last_price,
      div_yield_gross: pos.div_yield,
      div_yield_net_china_wht: pos.div_yield ? pos.div_yield * (1 - DEEP_DIVIDEND_USER_WHT) : null,
      shares: pos.shares,
      usd_value: pos.usd_value || pos.market_value,
    };
  }

  // 7. Stage 3: Analyzer (Opus)
  let analyzer_output = null;
  try {
    analyzer_output = await deepDividendAnalyzer(env, ticker, sector_bucket, extractions, historian, baseline);
  } catch (e) {
    console.error(`[deep-dividend] analyzer failed for ${ticker}:`, e.message);
    return { ok: false, error: `Analyzer failed: ${e.message}`, partial: { extractions: extractions.length, historian: !!historian } };
  }

  // 8. Stage 4: Devil's Advocate (Opus)
  let devils_advocate = null;
  try {
    devils_advocate = await deepDividendDevilsAdvocate(env, ticker, analyzer_output);
  } catch (e) {
    console.error(`[deep-dividend] devils_advocate failed for ${ticker}:`, e.message);
    devils_advocate = { error: e.message };
  }

  // 9. Cross-validation
  const verdict_action = analyzer_output?.["7_verdict"]?.action || "HOLD";
  const cut_prob = analyzer_output?.["4_thesis_impact"]?.dividend_cut_probability_3y || 0;
  const raise_prob = analyzer_output?.["4_thesis_impact"]?.dividend_raise_probability_12m || 0;
  let cross_validation = null;
  try {
    cross_validation = await deepDividendCrossValidate(env, ticker, verdict_action, cut_prob);
  } catch (e) {
    cross_validation = { error: e.message };
  }

  // 10. Compute composite score
  const safety = analyzer_output?.["2_dividend_safety"]?.score || 5;
  const growth = analyzer_output?.["2b_dividend_growth"]?.score || 5;
  const honesty = analyzer_output?.["2_dividend_safety"]?.honesty_score || 5;
  // Composite weights: safety 50%, growth 30%, honesty 20%
  const composite = Math.round((safety * 0.5 + growth * 0.3 + honesty * 0.2) * 10) / 10;

  // 11. Apply Devil's Advocate calibration
  let final_verdict = verdict_action;
  let final_confidence = analyzer_output?.["7_verdict"]?.confidence || "medium";
  if (devils_advocate?.calibration_recommendation?.should_lower_confidence && final_confidence === "high") {
    final_confidence = "medium";
  }
  if (devils_advocate?.calibration_recommendation?.should_change_verdict && devils_advocate?.calibration_recommendation?.suggested_verdict) {
    // Only auto-apply if the change is conservative (towards HOLD/TRIM, not towards more aggressive BUY)
    const fromAggression = ["STRONG_BUY", "BUY", "ACCUMULATE"].indexOf(verdict_action);
    const toAggression = ["STRONG_BUY", "BUY", "ACCUMULATE"].indexOf(devils_advocate.calibration_recommendation.suggested_verdict);
    if (fromAggression >= 0 && toAggression < fromAggression) {
      final_verdict = devils_advocate.calibration_recommendation.suggested_verdict;
    }
  }

  // 12. Auto-lower confidence if cross-validation conflict
  if (cross_validation?.conflict_detected && final_confidence === "high") {
    final_confidence = "medium";
  }

  // Inject final calibrated verdict back into output
  if (analyzer_output?.["7_verdict"]) {
    analyzer_output["7_verdict"]._original_verdict = verdict_action;
    analyzer_output["7_verdict"]._original_confidence = analyzer_output["7_verdict"].confidence;
    analyzer_output["7_verdict"].action = final_verdict;
    analyzer_output["7_verdict"].confidence = final_confidence;
  }

  const red_flags_count = (analyzer_output?.["3_red_and_green_flags"]?.red || []).length;
  const green_flags_count = (analyzer_output?.["3_red_and_green_flags"]?.green || []).length;
  const moat_score = analyzer_output?.["2_dividend_safety"]?.moat_score || null;

  // 13. Store in deep_dividend_analysis
  const now = Math.floor(Date.now() / 1000);
  let stored_id = null;
  try {
    const ins = await env.DB.prepare(`
      INSERT OR REPLACE INTO deep_dividend_analysis
      (ticker, quarter, sector_bucket, safety_score, growth_score, honesty_score,
       moat_score, capital_alloc_score, composite_score, verdict, confidence,
       cut_probability_3y, raise_probability_12m, red_flags_count, green_flags_count,
       result_json, devils_advocate_json, cross_validation_json,
       extraction_ids, model_extractor, model_historian, model_analyzer, created_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).bind(
      ticker, latestQuarter, sector_bucket,
      safety, growth, honesty,
      moat_score, null, composite,
      final_verdict, final_confidence,
      cut_prob, raise_prob,
      red_flags_count, green_flags_count,
      JSON.stringify(analyzer_output),
      JSON.stringify(devils_advocate),
      JSON.stringify(cross_validation),
      JSON.stringify(extractions.map((_, i) => i)),
      "claude-haiku-4-5-20251001",
      "claude-haiku-4-5-20251001",
      "claude-opus-4-20250514",
      now
    ).run();
    stored_id = ins.meta?.last_row_id;
  } catch (e) {
    console.error(`[deep-dividend] D1 insert failed for ${ticker}:`, e.message);
  }

  // 14. Track in agent_predictions for postmortem
  try {
    await env.DB.prepare(`
      INSERT OR REPLACE INTO agent_predictions
      (agent_name, ticker, prediction_date, verdict, confidence, safety_score, growth_score,
       cut_probability_3y, raise_probability_12m, prediction_json)
      VALUES ('deep_dividend', ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).bind(
      ticker, now, final_verdict, final_confidence,
      safety, growth, cut_prob, raise_prob,
      JSON.stringify({ verdict: final_verdict, scores: { safety, growth, honesty, composite } })
    ).run();
  } catch (e) {
    console.error(`[deep-dividend] agent_predictions insert failed:`, e.message);
  }

  return {
    ok: true,
    ticker,
    quarter: latestQuarter,
    sector_bucket,
    cached: false,
    pipeline: {
      extractions_run: extractions.length,
      historian_run: !!historian && !historian.error,
      analyzer_run: !!analyzer_output,
      devils_advocate_run: !!devils_advocate && !devils_advocate.error,
      cross_validation_agreement: cross_validation?.agreement_pct,
      cross_validation_conflict: !!cross_validation?.conflict_detected,
    },
    scores: { safety, growth, honesty, composite, moat: moat_score },
    verdict: { action: final_verdict, confidence: final_confidence },
    cut_probability_3y: cut_prob,
    raise_probability_12m: raise_prob,
    result: analyzer_output,
    devils_advocate,
    cross_validation,
    stored_id,
  };
}

// ═══════════════════════════════════════════════════════════════
// SMART ALERTS LAYER (2026-04-09)
// ═══════════════════════════════════════════════════════════════
//
// 4 alert types with high signal-to-noise:
//   1. 8-K material events (CEO change, impairment, restatement)
//   2. Insider clusters pre-earnings (3+ insiders, 60d window)
//   3. Cross-validation conflicts (deep verdict disagrees with deterministic agents)
//   4. Track record evaluator (postmortem of agent_predictions)
//
// All 4 use the existing push notification infrastructure (sendWebPush).
// Anti-fatigue: hard cap 3 push/day across all alert types, deduplication.
// ═══════════════════════════════════════════════════════════════

// Anti-fatigue: returns true if alert was sent in last 24h for same ticker+type
async function smartAlertWasRecentlySent(env, ticker, alert_type) {
  const cutoff = Math.floor(Date.now() / 1000) - 86400;
  try {
    const r = await env.DB.prepare(
      `SELECT 1 FROM material_events_8k WHERE ticker = ? AND event_type = ? AND processed_at >= ? AND alert_sent = 1 LIMIT 1`
    ).bind(ticker, alert_type, cutoff).first();
    return !!r;
  } catch { return false; }
}

// ─── 8-K material event tracker ──────────────────────────────────
// Polls SEC EDGAR submissions API for portfolio tickers.
// Detects items 5.02 (mgmt change), 2.05 (impairment), 4.01 (auditor change),
// 4.02 (restatement), 1.01 (material agreement), 8.01 (other material).
const SEC_EDGAR_BASE = "https://data.sec.gov/submissions";
const SEC_USER_AGENT = "AyR Deep Dividend Analyzer dev@ayr.local";

const CRITICAL_8K_ITEMS = {
  "5.02": { type: "mgmt_change", severity: "HIGH", label: "Departure or appointment of officer/director" },
  "2.05": { type: "impairment", severity: "HIGH", label: "Costs associated with exit or disposal" },
  "2.06": { type: "impairment", severity: "HIGH", label: "Material impairments" },
  "4.01": { type: "auditor_change", severity: "CRITICAL", label: "Changes in registrant's certifying accountant" },
  "4.02": { type: "restatement", severity: "CRITICAL", label: "Non-reliance on previously issued financial statements" },
  "1.01": { type: "material_agreement", severity: "MEDIUM", label: "Entry into material definitive agreement" },
  "1.03": { type: "bankruptcy", severity: "CRITICAL", label: "Bankruptcy or receivership" },
  "8.01": { type: "other_material", severity: "MEDIUM", label: "Other material events" },
};

async function fetch8KFilingsForCIK(cik) {
  // CIK must be 10-digit padded
  const padded = String(cik).padStart(10, '0');
  const url = `${SEC_EDGAR_BASE}/CIK${padded}.json`;
  try {
    const r = await fetch(url, { headers: { 'User-Agent': SEC_USER_AGENT } });
    if (!r.ok) return null;
    const data = await r.json();
    const recent = data?.filings?.recent;
    if (!recent) return null;
    const out = [];
    for (let i = 0; i < (recent.form || []).length; i++) {
      if (recent.form[i] === '8-K') {
        out.push({
          accession: recent.accessionNumber[i],
          filing_date: recent.filingDate[i],
          report_date: recent.reportDate?.[i] || null,
          items: recent.items?.[i] || '',
          primary_doc: recent.primaryDocument[i],
        });
      }
    }
    return out;
  } catch (e) {
    console.error(`[8K] fetch failed for CIK ${cik}:`, e.message);
    return null;
  }
}

async function process8KFilingsForTicker(env, ticker, cik) {
  const filings = await fetch8KFilingsForCIK(cik);
  if (!filings) return { ok: false, processed: 0 };
  let inserted = 0;
  const sevenDaysAgo = Date.now() - 7 * 86400000;
  for (const filing of filings) {
    const filingMs = new Date(filing.filing_date).getTime();
    if (filingMs < sevenDaysAgo) break; // recent only
    // Parse items: "5.02,9.01" → ["5.02","9.01"]
    const itemList = String(filing.items || '').split(',').map(s => s.trim()).filter(Boolean);
    let highestSeverity = null;
    let primaryEventType = null;
    let label = null;
    for (const item of itemList) {
      const known = CRITICAL_8K_ITEMS[item];
      if (known) {
        if (!highestSeverity || (known.severity === 'CRITICAL') || (known.severity === 'HIGH' && highestSeverity !== 'CRITICAL')) {
          highestSeverity = known.severity;
          primaryEventType = known.type;
          label = known.label;
        }
      }
    }
    if (!highestSeverity) continue; // skip non-material 8-Ks
    try {
      const r = await env.DB.prepare(`
        INSERT OR IGNORE INTO material_events_8k
        (ticker, filing_date, accession_number, item_codes, event_type, event_summary, severity, raw_url, processed_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
      `).bind(
        ticker,
        filing.filing_date,
        filing.accession,
        itemList.join(','),
        primaryEventType,
        label,
        highestSeverity,
        `https://www.sec.gov/cgi-bin/browse-edgar?action=getcompany&CIK=${cik}&type=8-K`,
        Math.floor(Date.now() / 1000)
      ).run();
      if (r.meta?.changes > 0) inserted++;
    } catch (e) { /* dup */ }
  }
  return { ok: true, processed: filings.length, inserted };
}

// Cron-callable: scan all portfolio tickers for new 8-K events
async function run8KMaterialEventsAgent(env) {
  // Need ticker → CIK mapping. The sec_filings agent stores CIK cache in
  // agent_memory table under key "sec_cik_cache" (NOT in a sec_filings_cik table
  // which doesn't exist). Bug discovered 2026-04-16 during full audit.
  let mapping = {};
  try {
    const row = await env.DB.prepare(
      `SELECT value FROM agent_memory WHERE key = 'sec_cik_cache'`
    ).first();
    if (row?.value) mapping = JSON.parse(row.value) || {};
  } catch {}
  if (Object.keys(mapping).length === 0) {
    return { ok: false, reason: "no CIK mapping available (run sec_filings agent first)" };
  }
  // Iterate portfolio
  const positions = await env.DB.prepare(
    `SELECT ticker FROM positions WHERE shares > 0`
  ).all();
  const portfolio = (positions.results || []).map(p => p.ticker);
  const results = [];
  for (const ticker of portfolio) {
    const cik = mapping[ticker];
    if (!cik) continue;
    try {
      const r = await process8KFilingsForTicker(env, ticker, cik);
      if (r.inserted > 0) results.push({ ticker, inserted: r.inserted });
    } catch (e) {
      results.push({ ticker, error: e.message });
    }
    // Polite rate limit for SEC
    await new Promise(r => setTimeout(r, 100));
  }
  return { ok: true, scanned: portfolio.length, with_new_events: results.length, results };
}

// ─── Insider cluster detector ────────────────────────────────────
// Reads existing insider data (from FMP, populated by runInsiderAgent)
// and looks for 3+ non-10b5-1 transactions same direction in 60d window
// preceding the next earnings date.
async function runInsiderClusterDetector(env) {
  const today = new Date();
  const sixtyDaysAgo = new Date(today.getTime() - 60 * 86400000).toISOString().slice(0, 10);
  // The agent_insights table has insider data; we look for patterns
  const positions = await env.DB.prepare(
    `SELECT ticker FROM positions WHERE shares > 0`
  ).all();
  const portfolio = (positions.results || []).map(p => p.ticker);
  const clusters = [];
  for (const ticker of portfolio) {
    try {
      // Get the most recent insider insight for this ticker
      const ins = await env.DB.prepare(`
        SELECT details FROM agent_insights
        WHERE agent_name = 'insider' AND ticker = ? AND fecha >= ?
        ORDER BY fecha DESC LIMIT 1
      `).bind(ticker, sixtyDaysAgo).first();
      if (!ins?.details) continue;
      let details;
      try { details = JSON.parse(ins.details); } catch { continue; }
      // Look for cluster signals in the details
      // The runInsiderAgent stores: {transactions: [...], net_buys, net_sells, cluster_buys, cluster_sells}
      const buyCluster = details.cluster_buys || 0;
      const sellCluster = details.cluster_sells || 0;
      if (buyCluster >= 3 || sellCluster >= 3) {
        const direction = buyCluster > sellCluster ? 'buy' : 'sell';
        const n_insiders = Math.max(buyCluster, sellCluster);
        // Check if we already alerted this cluster
        const exists = await env.DB.prepare(
          `SELECT 1 FROM insider_clusters WHERE ticker = ? AND window_end = ? AND direction = ?`
        ).bind(ticker, today.toISOString().slice(0, 10), direction).first();
        if (exists) continue;
        const severity = n_insiders >= 5 ? 'HIGH' : 'MEDIUM';
        await env.DB.prepare(`
          INSERT OR IGNORE INTO insider_clusters
          (ticker, window_start, window_end, direction, n_insiders, severity, detected_at)
          VALUES (?, ?, ?, ?, ?, ?, ?)
        `).bind(
          ticker, sixtyDaysAgo, today.toISOString().slice(0, 10),
          direction, n_insiders, severity, Math.floor(Date.now() / 1000)
        ).run();
        clusters.push({ ticker, direction, n_insiders, severity });
      }
    } catch (e) { /* skip */ }
  }
  return { ok: true, scanned: portfolio.length, clusters_found: clusters.length, clusters };
}

// ─── Cross-validation conflict scanner ───────────────────────────
// Reads latest deep_dividend_analysis rows and surfaces ones where the
// agent disagrees with deterministic signals.
async function runCrossValidationConflictScanner(env) {
  const since = Math.floor(Date.now() / 1000) - 7 * 86400; // last 7 days
  const rs = await env.DB.prepare(`
    SELECT id, ticker, verdict, confidence, cross_validation_json
    FROM deep_dividend_analysis
    WHERE created_at >= ?
  `).bind(since).all();
  const conflicts = [];
  for (const r of (rs.results || [])) {
    try {
      const cv = JSON.parse(r.cross_validation_json || '{}');
      if (cv.conflict_detected) {
        conflicts.push({
          id: r.id,
          ticker: r.ticker,
          deep_verdict: r.verdict,
          deep_confidence: r.confidence,
          agreement_pct: cv.agreement_pct,
          sources: cv.sources,
        });
      }
    } catch {}
  }
  return { ok: true, n_analyses_checked: rs.results?.length || 0, conflicts_found: conflicts.length, conflicts };
}

// ─── Track record evaluator (postmortem) ─────────────────────────
// Cron-friendly: evaluate predictions made 30/90/180/365 days ago
// against actual outcomes, populate brier_score and div_outcome columns.
async function runTrackRecordEvaluator(env) {
  const now = Math.floor(Date.now() / 1000);
  const checkpoints = [
    { days: 30,  field: 'div_outcome_30d',  retField: 'total_return_30d' },
    { days: 90,  field: 'div_outcome_90d',  retField: 'total_return_90d' },
    { days: 180, field: 'div_outcome_180d', retField: 'total_return_180d' },
    { days: 365, field: 'div_outcome_365d', retField: 'total_return_365d' },
  ];
  let totalEvaluated = 0;
  for (const cp of checkpoints) {
    const targetTs = now - cp.days * 86400;
    const tolerance = 86400; // ±1 day
    // Find predictions in the window that don't have this checkpoint evaluated yet
    const rs = await env.DB.prepare(`
      SELECT id, agent_name, ticker, prediction_date, verdict, cut_probability_3y, raise_probability_12m
      FROM agent_predictions
      WHERE prediction_date BETWEEN ? AND ?
        AND ${cp.field} IS NULL
      LIMIT 100
    `).bind(targetTs - tolerance, targetTs + tolerance).all();
    for (const pred of (rs.results || [])) {
      try {
        // Check dividendos table for cut/raise/maintained between prediction_date and now
        const start = new Date(pred.prediction_date * 1000).toISOString().slice(0, 10);
        const end = new Date((pred.prediction_date + cp.days * 86400) * 1000).toISOString().slice(0, 10);
        const divs = await env.DB.prepare(
          `SELECT bruto, fecha FROM dividendos WHERE ticker = ? AND fecha BETWEEN ? AND ? ORDER BY fecha ASC`
        ).bind(pred.ticker, start, end).all();
        const divList = (divs.results || []).map(d => Number(d.bruto) || 0);
        let outcome = 'maintained';
        if (divList.length >= 2) {
          const first = divList[0];
          const last = divList[divList.length - 1];
          if (last < first * 0.95) outcome = 'cut';
          else if (last > first * 1.02) outcome = 'raised';
          else outcome = 'maintained';
        } else if (divList.length === 0) {
          outcome = 'no_dividend_paid';
        }
        // Update the prediction row
        await env.DB.prepare(
          `UPDATE agent_predictions SET ${cp.field} = ?, evaluated_at = ? WHERE id = ?`
        ).bind(outcome, now, pred.id).run();
        // Compute brier score for this prediction (only at 365d)
        if (cp.days === 365 && pred.cut_probability_3y !== null) {
          const cutHappened = outcome === 'cut' ? 1 : 0;
          const brier = Math.pow(pred.cut_probability_3y - cutHappened, 2);
          const cut_correct = (pred.cut_probability_3y >= 0.5 ? 1 : 0) === cutHappened ? 1 : 0;
          await env.DB.prepare(
            `UPDATE agent_predictions SET brier_score = ?, cut_correct = ? WHERE id = ?`
          ).bind(brier, cut_correct, pred.id).run();
        }
        totalEvaluated++;
      } catch (e) {
        console.error(`[track-record] eval failed for prediction ${pred.id}:`, e.message);
      }
    }
  }
  return { ok: true, total_evaluated: totalEvaluated };
}

// ─── Daily Briefing builder ──────────────────────────────────────
// Synthesizes everything into a 1-page actionable email/dashboard.
async function buildDailyBriefing(env) {
  const today = new Date().toISOString().slice(0, 10);
  const lookbackTs = Math.floor(Date.now() / 1000) - 24 * 3600;

  // 1. Action required (deep dividend TRIM/SELL)
  const actionReq = await env.DB.prepare(`
    SELECT ticker, verdict, confidence, composite_score, cut_probability_3y, red_flags_count
    FROM deep_dividend_analysis
    WHERE verdict IN ('TRIM','SELL')
    ORDER BY composite_score ASC, created_at DESC LIMIT 5
  `).all();

  // 2. New 8-K events in last 24h
  const new8K = await env.DB.prepare(`
    SELECT ticker, item_codes, event_type, severity, filing_date
    FROM material_events_8k
    WHERE processed_at >= ?
    ORDER BY processed_at DESC LIMIT 10
  `).bind(lookbackTs).all();

  // 3. New insider clusters in last 24h
  const newClusters = await env.DB.prepare(`
    SELECT ticker, direction, n_insiders, severity
    FROM insider_clusters
    WHERE detected_at >= ?
    ORDER BY detected_at DESC LIMIT 10
  `).bind(lookbackTs).all();

  // 4. Earnings this week (placeholder — needs earnings calendar data)
  // For now, use the last 7 days of new transcripts as proxy
  const recentTranscripts = await env.DB.prepare(`
    SELECT DISTINCT ticker FROM earnings_documents
    WHERE doc_type = 'TRANSCRIPT' AND filing_date >= date('now', '-7 days')
    ORDER BY filing_date DESC LIMIT 10
  `).all();

  // 5. Top opportunities (BUY/ACCUMULATE high composite)
  const topOps = await env.DB.prepare(`
    SELECT ticker, verdict, confidence, composite_score, raise_probability_12m
    FROM deep_dividend_analysis
    WHERE verdict IN ('STRONG_BUY','BUY','ACCUMULATE')
    ORDER BY composite_score DESC, created_at DESC LIMIT 5
  `).all();

  // 6. Cross-validation conflicts
  const conflictsScanner = await runCrossValidationConflictScanner(env);

  // 7. Track record snapshot
  const trackRecord = await env.DB.prepare(`
    SELECT
      COUNT(*) as n_total,
      SUM(CASE WHEN cut_correct = 1 THEN 1 ELSE 0 END) as n_cut_correct,
      AVG(brier_score) as avg_brier
    FROM agent_predictions
    WHERE agent_name = 'deep_dividend' AND brier_score IS NOT NULL
  `).first();

  // 8. Top news last 24h (design-doc integration: relevance >= 0.5 = 50/100)
  let topNews = [];
  try {
    const yesterday = new Date(Date.now() - 86400000).toISOString();
    const newsRs = await env.DB.prepare(`
      SELECT id, title, summary, source, published_at, tickers_json, severity, relevance_score, category
        FROM news_items
       WHERE published_at >= ? AND relevance_score >= 0.5
       ORDER BY relevance_score DESC, published_at DESC
       LIMIT 30
    `).bind(yesterday).all();
    topNews = (newsRs.results || []).map(r => ({
      id: r.id,
      title: r.title,
      summary: r.summary,
      source: r.source,
      published_at: r.published_at,
      tickers: (() => { try { return JSON.parse(r.tickers_json || '[]'); } catch (_) { return []; } })(),
      severity: r.severity,
      relevance_score: r.relevance_score,
      category: r.category,
    }));
  } catch (_) { /* non-fatal */ }

  return {
    ok: true,
    date: today,
    sections: {
      action_required: actionReq.results || [],
      new_8k_events: new8K.results || [],
      new_insider_clusters: newClusters.results || [],
      earnings_this_week: (recentTranscripts.results || []).map(r => r.ticker),
      top_opportunities: topOps.results || [],
      cross_validation_conflicts: conflictsScanner.conflicts || [],
      top_news: topNews,
      track_record: {
        n_total_evaluated: trackRecord?.n_total || 0,
        n_cut_correct: trackRecord?.n_cut_correct || 0,
        avg_brier_score: trackRecord?.avg_brier || null,
        baseline_random_brier: 0.25,
      },
    },
    generated_at: new Date().toISOString(),
  };
}

// ─── Helper: Enrich Position Sectors ────────────────────────────
async function enrichPositionSectors(env) {
  const { results: positions } = await env.DB.prepare(
    "SELECT ticker, sector FROM positions WHERE shares > 0"
  ).all();

  // Manual sector mappings — ONLY for ETFs/preferred that APIs don't cover.
  // International stocks (BME:/HKG:/etc.) are now resolved via FMP Ultimate /v3/profile.
  // Previous hardcoded HKG entries were WRONG (HKG:1052=Industrials not Healthcare,
  // HKG:2219=Healthcare not Tech, HKG:1910=Consumer Cyclical not Tech) — removed.
  const MANUAL_SECTORS = {
    'NET.UN': 'Real Estate', 'IIPR-PRA': 'Real Estate',
    'BIZD': 'Financial Services', 'DIVO': 'Financial Services',
    'SPHD': 'Financial Services', 'WEEL': 'Financial Services',
  };

  const missing = positions.filter(p => !p.sector || p.sector === 'Unknown' || p.sector === '');
  if (!missing.length) return { updated: 0, total: positions.length, message: "All sectors filled" };

  let updated = 0;

  // Apply manual mappings first
  for (const pos of missing) {
    if (MANUAL_SECTORS[pos.ticker]) {
      await env.DB.prepare("UPDATE positions SET sector = ? WHERE ticker = ?").bind(MANUAL_SECTORS[pos.ticker], pos.ticker).run();
      updated++;
    }
  }
  const tickers = missing.map(p => p.ticker);

  // 1. Try GuruFocus cache first
  const gfMap = await getGfData(env, tickers);

  // 2. Try FMP fundamentals profile
  const placeholders = tickers.map(() => "?").join(",");
  const { results: fmpRows } = await env.DB.prepare(
    `SELECT symbol, profile FROM fundamentals WHERE symbol IN (${placeholders})`
  ).bind(...tickers).all();
  const fmpMap = {};
  for (const f of fmpRows) {
    if (f.profile) {
      try {
        const p = JSON.parse(f.profile);
        const profile = Array.isArray(p) ? p[0] : p;
        if (profile?.sector) fmpMap[f.symbol] = profile.sector;
      } catch {}
    }
  }

  // 3. On-demand FMP /v3/profile fetch for tickers still missing sector
  //    (covers international tickers not yet in fundamentals table)
  const FMP_KEY = env.FMP_KEY;
  const fmpProfileMap = {};
  if (FMP_KEY) {
    const stillMissing = missing.filter(p => !gfMap[p.ticker]?.sector && !fmpMap[p.ticker]);
    for (let i = 0; i < stillMissing.length; i += 10) {
      const batch = stillMissing.slice(i, i + 10);
      await Promise.all(batch.map(async (pos) => {
        try {
          const sym = toFMP(pos.ticker);
          const r = await fetch(`https://financialmodelingprep.com/stable/profile?symbol=${encodeURIComponent(sym)}&apikey=${FMP_KEY}`);
          if (!r.ok) return;
          const d = await r.json();
          const profile = Array.isArray(d) ? d[0] : d;
          if (profile?.sector) fmpProfileMap[pos.ticker] = profile.sector;
        } catch {}
      }));
    }
  }

  // 4. Update positions with sector data
  for (const pos of missing) {
    const sector = gfMap[pos.ticker]?.sector || fmpMap[pos.ticker] || fmpProfileMap[pos.ticker] || null;
    if (sector) {
      await env.DB.prepare("UPDATE positions SET sector = ? WHERE ticker = ?").bind(sector, pos.ticker).run();
      updated++;
    }
  }

  return { updated, missing: missing.length, total: positions.length };
}

// ─── Helper: Cache Market Indicators (FMP Ultimate) ────────────
async function cacheMarketIndicators(env) {
  const MARKET_TICKERS = [
    'SPY','QQQ','IWM','DIA',                          // indices
    'XLK','XLF','XLE','XLV','XLU','XLP','XLI','XLRE', // sectors
    'HYG','LQD','TLT','SHY',                          // credit
    'QUAL','MTUM','VLUE',                              // factors
    'GLD','USO','DBC',                                 // commodities
    'UUP',                                             // dollar
    '^VIX',                                            // volatility
  ];

  // Single batch quote call (FMP supports up to 50 symbols in one URL)
  const quotes = await fmpQuote(MARKET_TICKERS, env);
  const results = {};

  // Sparklines in parallel batches of 10
  for (let i = 0; i < MARKET_TICKERS.length; i += 10) {
    const batch = MARKET_TICKERS.slice(i, i + 10);
    const sparks = await Promise.all(batch.map(t => fmpSpark(t, env, 5)));
    batch.forEach((ticker, idx) => {
      const q = quotes[ticker];
      if (!q || q.price == null) return;
      const closes = sparks[idx] || [];
      const price = q.price;
      const prevClose = q.previousClose || price;
      const firstClose = closes.length > 1 ? closes[0] : prevClose;
      results[ticker] = {
        ticker, price,
        changePct: prevClose ? ((price - prevClose) / prevClose * 100) : 0,
        change5dPct: firstClose ? ((price - firstClose) / firstClose * 100) : 0,
        spark5d: closes.slice(-5),
      };
    });
  }

  // Store in agent_memory
  await env.DB.prepare(
    `INSERT INTO agent_memory (id, data, updated_at) VALUES ('market_indicators', ?, datetime('now'))
     ON CONFLICT(id) DO UPDATE SET data = excluded.data, updated_at = datetime('now')`
  ).bind(JSON.stringify(results)).run();

  return results;
}

// ─── Helper: Get Market Indicators from cache ───��──────────────
async function getMarketIndicators(env) {
  const row = await env.DB.prepare("SELECT data FROM agent_memory WHERE id = 'market_indicators'").first();
  return row?.data ? JSON.parse(row.data) : {};
}

